PRAGMA foreign_keys = ON;
DROP TABLE IF EXISTS chaupai_verses;
CREATE TABLE chaupai_verses (
  id TEXT PRIMARY KEY,
  source_type TEXT NOT NULL,
  title TEXT NOT NULL,
  day_index INTEGER,
  date TEXT,
  gurmukhi_text TEXT NOT NULL,
  english_meaning TEXT NOT NULL,
  simple_explanation TEXT NOT NULL,
  life_reflection TEXT NOT NULL,
  is_featured INTEGER NOT NULL DEFAULT 0,
  audio_file_name TEXT,
  tags_json TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_chaupai_day_index ON chaupai_verses(day_index);
CREATE INDEX idx_chaupai_title ON chaupai_verses(title);
